import torch
import torch.nn.functional as F
from torchvision import models, transforms
from flask import Flask, request, jsonify
from PIL import Image
import io
import numpy as np

app = Flask(__name__)

# Load pre-trained model
model = models.resnet50(pretrained=True)
model.eval()

# Image preprocessing
preprocess = transforms.Compose([
    transforms.Resize(256),
    transforms.CenterCrop(224),
    transforms.ToTensor(),
    transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225]),
])

# Load ImageNet class labels
with open('imagenet_classes.txt', 'r') as f:
    labels = [line.strip() for line in f.readlines()]

# Add adversarial detection
def detect_adversarial(image_tensor):
    # Simple gradient-based detection
    image_tensor.requires_grad = True
    output = model(image_tensor)
    loss = torch.max(output)
    loss.backward()
    
    # Check for large gradients
    grad_norm = torch.norm(image_tensor.grad.data)
    if grad_norm > 1000:  # Threshold for adversarial detection
        return True
    return False

@app.route('/classify', methods=['POST'])
def classify_image():
    try:
        # Get image from request
        file = request.files['image']
        image = Image.open(io.BytesIO(file.read())).convert('RGB')
        
        # Preprocess image
        input_tensor = preprocess(image).unsqueeze(0)
        
        # Check for adversarial examples
        if detect_adversarial(input_tensor):
            return jsonify({'error': 'Potential adversarial example detected'}), 400
        
        # Run inference
        with torch.no_grad():
            output = model(input_tensor)
            probabilities = F.softmax(output, dim=1)
            confidence, predicted = torch.max(probabilities, 1)
            
            # Return results
            return jsonify({
                'class': labels[predicted.item()],
                'confidence': confidence.item()
            })
            
    except Exception as e:
        return jsonify({'error': str(e)}), 400

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)